package com.example.lessondesign.dao; import com.example.lessondesign.bean.ImageResource; import org.apache.ibatis.annotations.*; import java.util.*; @Mapper public interface ImageResourceDao { @Select("SELECT * FROM image_resource LIMIT #{size} OFFSET #{offset}") List<ImageResource> selectAll(@Param("offset") int offset, @Param("size") int size); @Select("SELECT COUNT(*) FROM image_resource") int countAll(); @Select("SELECT * FROM image_resource WHERE id=#{id}") ImageResource selectById(@Param("id") long id); @Update("UPDATE image_resource SET favorite=#{favorite} WHERE id=#{id}") void update(ImageResource r); }